import openpyxl,json
from collections import defaultdict
p=r'C:\Users\62490\Downloads\广告搜索词_ACEEDU_DE_20260527-20260604.xlsx'
wb=openpyxl.load_workbook(p, read_only=True, data_only=True)
ws=wb['广告搜索词']
rows=list(ws.iter_rows(values_only=True)); headers=list(rows[0])
data=[]
for r in rows[2:]:
    if not r or not r[1]:
        continue
    d=dict(zip(headers,r))
    for k in ['花费','曝光量','点击量','订单数','销售额']:
        d[k]=float(d.get(k) or 0)
    data.append(d)

def summarize(items):
    spend=sum(x['花费'] for x in items); imp=sum(x['曝光量'] for x in items); clicks=sum(x['点击量'] for x in items); orders=sum(x['订单数'] for x in items); sales=sum(x['销售额'] for x in items)
    return {'rows':len(items),'spend':round(spend,2),'impressions':int(imp),'clicks':int(clicks),'ctr':round(clicks/imp,4) if imp else 0,'cpc':round(spend/clicks,2) if clicks else 0,'orders':int(orders),'sales':round(sales,2),'cvr':round(orders/clicks,4) if clicks else 0,'acos':round(spend/sales,4) if sales else None,'roas':round(sales/spend,2) if spend else None}

def line(d):
    base={k:d.get(k) for k in ['用户搜索词','关键词/投放方式','匹配/定位','广告活动','广告组']}
    base.update(summarize([d])); return base
out={}
out['total']=summarize(data)
for group_col in ['广告活动','广告组','匹配/定位']:
    groups=defaultdict(list)
    for d in data: groups[d[group_col]].append(d)
    arr=[]
    for k,v in groups.items():
        rec={group_col:k}; rec.update(summarize(v)); arr.append(rec)
    out[group_col]=sorted(arr, key=lambda x:(-x['spend'], str(x[group_col])))
conv=[d for d in data if d['订单数']>0]
non=[d for d in data if d['订单数']==0]
out['converting']=sorted([line(d) for d in conv], key=lambda x:(x['acos'] if x['acos'] is not None else 999, -x['orders']))
out['non_top_spend']=sorted([line(d) for d in non], key=lambda x:-x['spend'])[:20]
out['zero_click_ge2']=[line(d) for d in sorted(non, key=lambda x:-x['点击量']) if d['点击量']>=2]
mag=[d for d in data if 'magnet' in (str(d.get('用户搜索词') or '')+' '+str(d.get('关键词/投放方式') or '')).lower()]
out['magnet']=summarize(mag)
out['magnet_rows']=sorted([line(d) for d in mag], key=lambda x:-x['spend'])
print(json.dumps(out,ensure_ascii=False,indent=2))
